const https = require('https');
const querystring = require('querystring');

const API_KEY = 'AIzaSyBhmoUCGTCYVIPW1Y_Dlvapv7w7H7U_T4Y';
const items = $input.all();
const out = [];

async function fetchPlaceDetails(placeId) {
  return new Promise((resolve, reject) => {
    const qs = querystring.stringify({
      place_id: placeId,
      fields: 'website,formatted_phone_number',
      key: API_KEY
    });
    const url = `https://maps.googleapis.com/maps/api/place/details/json?${qs}`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          resolve(parsed.result || {});
        } catch (e) {
          resolve({});
        }
      });
    }).on('error', () => resolve({}));
  });
}

// Process in batches to avoid overwhelming the API
const BATCH_SIZE = 5;
const DELAY_MS = 200;

async function processBatch(batch) {
  const promises = batch.map(async (item) => {
    const lead = item.json;
    const details = await fetchPlaceDetails(lead.place_id);

    return {
      json: {
        ...lead,
        website: details.website || null,
        phone: details.formatted_phone_number || null,
        place_details_status: details.website ? 'complete' : 'partial'
      }
    };
  });

  return Promise.all(promises);
}

async function main() {
  for (let i = 0; i < items.length; i += BATCH_SIZE) {
    const batch = items.slice(i, i + BATCH_SIZE);
    const results = await processBatch(batch);
    out.push(...results);

    if (i + BATCH_SIZE < items.length) {
      await new Promise(r => setTimeout(r, DELAY_MS));
    }
  }
  return out;
}

return main();

const results = [];

for (const item of $input.all()) {
  const lead = item.json;

  let score = 0;
  const flags = [];
  const tags = [];

  // -------------------------
  // NORMALIZATION (safe reads)
  // -------------------------
  const reviews = lead.review_count || 0;
  const rating = lead.rating || 0;
  const hasWebsite = !!lead.website;
  const hasPhone = !!lead.phone;
  const hasAddress = !!lead.address;

  // -------------------------
  // DEMAND SIGNALS
  // -------------------------
  if (reviews >= 200) { score += 30; tags.push("high_demand"); }
  else if (reviews >= 100) { score += 25; tags.push("strong_demand"); }
  else if (reviews >= 50) { score += 20; }
  else if (reviews >= 20) { score += 15; }
  else { score += 5; tags.push("low_competition"); }

  if (rating >= 4.7) { score += 20; tags.push("high_quality"); }
  else if (rating >= 4.5) { score += 15; }
  else if (rating >= 4.0) { score += 10; }
  else { flags.push("low_rating"); }

  // -------------------------
  // OPPORTUNITY SIGNALS
  // -------------------------
  if (!hasWebsite) {
    score += 15;
    flags.push("no_website");
    tags.push("service_opportunity_web");
  }

  if (!hasPhone) {
    score += 10;
    flags.push("no_phone");
  }

  if (!hasAddress) {
    score += 5;
    flags.push("no_address");
  }

  // -------------------------
  // BONUS SIGNALS
  // -------------------------
  if (reviews > 0 && rating >= 4.5 && !hasWebsite) {
    score += 10;
    tags.push("high_value_target");
  }

  // -------------------------
  // FINALIZE SCORE
  // -------------------------
  score = Math.min(score, 100);

  let tier = "COLD";
  if (score >= 75) tier = "HOT";
  else if (score >= 55) tier = "WARM";

  // -------------------------
  // OUTPUT STRUCTURE
  // -------------------------
  results.push({
    json: {
      ...lead,

      score,
      tier,

      // structured insights
      tags,
      flags,

      // useful booleans
      hasWebsite,
      hasPhone,
      hasAddress,

      // lead quality indicator
      completeness: [
        hasWebsite,
        hasPhone,
        hasAddress
      ].filter(Boolean).length / 3
    }
  });
}

return results;

const items = $input.all();

const hot = items.filter(i => i.json.tier === "HOT");
const warm = items.filter(i => i.json.tier === "WARM");

const summary = {
  total: items.length,
  hot: hot.length,
  warm: warm.length,
  top: hot
    .sort((a, b) => b.json.score - a.json.score)
    .slice(0, 5)
    .map(i => i.json),
  opportunity_breakdown: {
    no_website: items.filter(i => i.json.flags.includes("no_website")).length,
    no_phone: items.filter(i => i.json.flags.includes("no_phone")).length,
    low_rating: items.filter(i => i.json.flags.includes("low_rating")).length
  }
};

return [{ json: { _summary: summary } }];
